import React, { useEffect, useState } from 'react';
import axios from 'axios';

function Admin({ token }) {
    const [countries, setCountries] = useState([]);
   function decodeUnicode(str) {
  return str.replace(/\\u([\dA-F]{4})/gi, (match, grp) => {
    return String.fromCharCode(parseInt(grp, 16));
  });
}
useEffect(() => {
    axios.get('http://192.168.66.59:5000/api/countries')
      .then(response => {

        const decodedCountries = response.data.map(country => ({
          ...country,
          name: decodeUnicode(country.name),
        }));
        setCountries(decodedCountries);
        setLoading(false);
      })
      .catch(err => {
        setError('Failed to fetch countries. Please try again later.');
        setLoading(false);
        console.error('There was an error fetching countries!', err);
      });
  }, []);

  return (
    <div className="App">
      <h1>админская панель</h1>
      {error && <p className="error-message">{error}</p>}
      {loading ? <p>Загрузка стран...</p> : (
        <ul>
          {countries.map(country => (
            <li key={country.id}>{country.name}</li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default Admin;
